# from lambda_function.py
def handler(event, context):
    rrset = route53.list_resource_record_sets(
        HostedZoneId=HOSTED_ZONE_ID,
        StartRecordName=RECORD_NAME,
        StartRecordType='A',
        MaxItems='1',
    )['ResourceRecordSets'][0]
    current_ips = {r['Value'] for r in rrset['ResourceRecords']}
    target_health = elbv2.describe_target_health(TargetGroupArn=TARGET_GROUP_ARN)
    healthy_ips = {t['Target']['Id'] for t in target_health['TargetHealthDescriptions']
                   if t['TargetHealth']['State'] == 'healthy'}
    new_ips = (current_ips & healthy_ips) | healthy_ips  # keep healthy current, add newly healthy
    route53.change_resource_record_sets(
        HostedZoneId=HOSTED_ZONE_ID,
        ChangeBatch={
            'Changes': [{
                'Action': 'UPSERT',
                'ResourceRecordSet': {
                    'Name': RECORD_NAME, 'Type': 'A', 'TTL': int(TTL_SECONDS),
                    'ResourceRecords': [{'Value': ip} for ip in sorted(new_ips)]
                }
            }]
        }
    )
